fn fib(n: i32, memo: &mut HashMap<i32, i64>) -> i64 {
    if n <= 1 {
        return n as i64;
    }
    if let Some(&val) = memo.get(&n) {
        return val;
    }
    let result = fib(n - 1, memo) + fib(n - 2, memo);
    memo.insert(n, result);
    result
}

fn main() {
    let mut memo = HashMap::new();
    println!("{}", fib(50, &mut memo));  // 12586269025
}

