fn subsets(nums: &[i32], idx: usize, path: &mut Vec<i32>, result: &mut Vec<Vec<i32>>) {
    result.push(path.clone());
    for i in idx..nums.len() {
        path.push(nums[i]);
        subsets(nums, i + 1, path, result);
        path.pop();
    }
}

fn main() {
    let mut result = Vec::new();
    subsets(&[1, 2, 3], 0, &mut Vec::new(), &mut result);
    println!("{}", result.len());  // 8
    for s in &result {
        println!("{:?}", s);
    }
}

